INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "獣人族", "東山奈央", 100101, "ヒヨリ", "人助け、応援", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 2, "トゥインクルウィッシュ", 155, 44, 8, 16, 27, "人助けが大好き！　前向き格闘娘", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "ヒューマン", "種田梨沙", 100201, "ユイ", "料理、人間観察", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 2, "トゥインクルウィッシュ", 158, 47, 4, 17, 5, "戦闘のサポートが得意な、心優しい少女", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("B", "魔族", "早見沙織", 100301, "レイ", "読書、乗馬、お茶", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 2, "トゥインクルウィッシュ", 163, 46, 1, 18, 12, "クールで何事にも真っ直ぐな剣士", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "ヒューマン", "諸星すみれ", 100401, "ミソギ", "いたずら、探検", "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 5, "リトルリリカル", 128, 27, 8, 9, 10, "探検好きのイタズラっ子", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "獣人族", "下田麻美", 100501, "マツリ", "ヒーローごっこ", "？？？", 8, "王宮騎士団（NIGHTMARE）", 146, 40, 11, 12, 25, "ヒーローに憧れる騎士見習いの少女", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "魔族", "浅倉杏美", 100601, "アカリ", "サックス", "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 7, "悪魔偽王国軍（ディアボロス）", 150, 42, 11, 13, 22, "甘え上手なみんなの人気者", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("B", "魔族", "雨宮天", 100701, "ミヤコ", "プリンを食べること", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 7, "悪魔偽王国軍（ディアボロス）", 130, 32, 1, 14, 23, "プリン大好きゴースト娘", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("AB", "エルフ", "大空直美", 100801, "ユキ", "鏡で自分を見ること", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 15, "ヴァイスフリューゲル　ランドソル支部", 150, 40, 10, 14, 10, "ボクは誰よりも美しい", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "魔族", "髙野麻美", 100901, "アンナ", "小説執筆", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 13, "トワイライトキャラバン", 159, 45, 7, 17, 5, "前世を信じる中二病患者、「疾風の冥姫」", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "獣人族", "内田真礼", 101001, "マホ", "空想、ぬいぐるみ集め", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 10, "自警団（カォン）", 155, 42, 9, 16, 22, "マホマホ王国のプリンセス", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "ヒューマン", "阿澄佳奈", 101101, "リノ", "お裁縫", "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 3, "ラビリンス", 156, 44, 8, 15, 25, "人懐っこくてマシンガントークな妹系少女", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "エルフ", "大橋彩香", 101201, "ハツネ", "妹と遊ぶこと、二度寝、昼寝、早寝", "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 6, "フォレスティエ", 156, 46, 12, 17, 24, "みんなのために超能力を使う眠り姫", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "魔族", "佳村はるか", 101301, "ナナカ", "読書、魔法", "", 13, "トワイライトキャラバン", 166, 55, 8, 18, 21, "オタク全開な魔法少女", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("AB", "獣人族", "水瀬いのり", 101401, "カスミ", "読書、推理", "test", 10, "自警団（カォン）", 152, 41, 11, 15, 3, "頭脳明晰な美少女名探偵", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "エルフ", "國府田マリ子", 101501, "ミサト", "絵本作り", "test", 6, "フォレスティエ", 165, 54, 9, 21, 5, "母性溢れる優しいみんなの「ミサト先生」", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "魔族", "上坂すみれ", 101601, "スズナ", "ファッション", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 14, "ルーセント学院", 167, 48, 4, 17, 10, "天真爛漫で人気者のカリスマモデル", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "獣人族", "高森奈津美", 101701, "カオリ", "踊り、空手", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 10, "自警団（カォン）", 158, 53, 7, 17, 7, "いつでも「なんくるないさ～」な天然娘", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("B", "魔族", "伊藤静", 101801, "イオ", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 14, "ルーセント学院", 162, 52, 8, 23, 14, "多くの男性を魅了する無垢な女教師", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "獣人族", "日高里菜", 102001, "ミミ", "かわいいもの集め", "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 5, "リトルリリカル", 117, 21, 4, 10, 3, "お歌もにんじんも、ウサギさんも大好き♪", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("B", "ヒューマン", "植田佳奈", 102101, "クルミ", "観劇、おままごと", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 9, "サレンディア救護院", 150, 40, 6, 12, 9, "泣き虫で臆病な守ってあげたい女の子", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "魔族", "原紗友里", 102201, "ヨリ", "ゲーム全般", "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 7, "悪魔偽王国軍（ディアボロス）", 150, 40, 11, 13, 22, "人見知りであまのじゃくな女の子", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("B", "ヒューマン", "芹澤優", 102301, "アヤネ", "屋内でできる遊び", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 9, "サレンディア救護院", 148, 38, 5, 14, 10, "ぷうきちといつも一緒！", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "ヒューマン", "悠木碧", 102501, "スズメ", "ご奉仕", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 9, "サレンディア救護院", 154, 43, 12, 15, 12, "お嬢さまのためにがんばるドジっ娘メイド", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("B", "獣人族", "小岩井ことり", 102601, "リン", "あんパン", "test", 11, "牧場（エリザベスパーク）", 144, 42, 1, 17, 1, "遊びと睡眠が何より大事なぐうたら娘", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("B", "魔族", "橋本ちなみ", 102701, "エリコ", "実験、裁縫、料理", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 13, "トワイライトキャラバン", 154, 43, 7, 16, 30, "運命の相手に一途すぎる乙女", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "エルフ", "堀江由衣", 102801, "サレン", "経営、お茶会", "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 9, "サレンディア救護院", 156, 43, 10, 17, 4, "救護院を経営する優しい庶民派お嬢様", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("B", "ヒューマン", "日笠陽子", 102901, "ノゾミ", "舞台鑑賞、ダンス", "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", 4, "カルミナ", 157, 40, 1, 17, 24, "歌って踊れる大人気アイドル", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "ヒューマン", "佐藤聡美", 103001, "ニノン", "忍法開発", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 15, "ヴァイスフリューゲル　ランドソル支部", 163, 51, 8, 16, 31, "トーゴクの神秘、オシエテクダサイ！", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("AB", "魔族", "大坪由佳", 103101, "シノブ", "占い", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 7, "悪魔偽王国軍（ディアボロス）", 157, 42, 12, 18, 22, "占いが得意な霊能少女", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("AB", "ヒューマン", "松嵜麗", 103201, "アキノ", "慈善事業", "この私とともにいる限り、\nお金に不自由はさせませんわ！", 12, "メルクリウス財団", 157, 45, 3, 18, 12, "一人前の商人を目指すパワフルお嬢様", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("B", "ヒューマン", "新田恵海", 103301, "マヒル", "漫才", "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 11, "牧場（エリザベスパーク）", 142, 35, 3, 20, 3, "みんなを笑顔にするお笑い牧場主", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "エルフ", "今井麻美", 103401, "ユカリ", "ウインドーショッピング", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 12, "メルクリウス財団", 164, 55, 3, 22, 16, "純情でほっとけない大人の女性", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "エルフ", "小倉唯", 103601, "キョウカ", "お勉強", "test", 5, "リトルリリカル", 118, 21, 2, 8, 2, "礼儀正しくしっかり者のちびっ子優等生", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "ヒューマン", "茅原実里", 103701, "トモ", "剣術、年長者をからかう", "test", 8, "王宮騎士団（NIGHTMARE）", 149, 43, 8, 13, 11, "義理堅くてからかい好きな剣術少女", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "獣人族", "小清水亜美", 103801, "シオリ", "読書、お散歩", "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 11, "牧場（エリザベスパーク）", 153, 40, 11, 14, 3, "読書が趣味の病弱少女", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("AB", "エルフ", "花澤香菜", 104001, "アオイ", "友達作りのイメトレ", "友達ができるその日まで…\nBB団で\nトレーニングですっ！", 6, "フォレスティエ", 158, 44, 6, 13, 6, "「友達」に憧れる、エルフの森の女の子", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "ヒューマン", "福原綾香", 104201, "チカ", "各種楽器", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 4, "カルミナ", 163, 46, 6, 17, 3, "人々を守るために歌う、唱喚士の少女", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "獣人族", "小松未可子", 104301, "マコト", "お菓子作り", "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 10, "自警団（カォン）", 168, 54, 8, 17, 9, "男勝りで情に厚いワイルド娘", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "魔族", "丹下桜", 104401, "イリヤ", "世界征服", "test", 7, "悪魔偽王国軍（ディアボロス）", 172, 50, 5, "??", 5, "かつては夜を支配した最強の吸血鬼", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("AB", "ヒューマン", "長妻樹里", 104501, "クウカ", "小説を読むこと", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 15, "ヴァイスフリューゲル　ランドソル支部", 157, 49, 11, 18, 19, "妄想大好き！　ほんとは照れ屋な女の子", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("AB", "獣人族", "沼倉愛美", 104601, "タマキ", "猫とたわむれること", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 12, "メルクリウス財団", 158, 48, 3, 19, 1, "弱きを助け強きをくじく猫娘", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "ヒューマン", "川澄綾子", 104701, "ジュン", "格闘技、湯浴み", "？？？", 8, "王宮騎士団（NIGHTMARE）", 171, 50, 10, 25, 25, "素顔を見せない冷静沈着な女性騎士", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "ヒューマン", "田所あずさ", 104801, "ミフユ", "傭兵などのアルバイト", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 12, "メルクリウス財団", 163, 49, 11, 20, 11, "仕事も私事も効率優先な傭兵少女", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "ヒューマン", "生天目仁美", 104901, "シズル", "家事全般", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 3, "ラビリンス", 168, 54, 10, 18, 24, "お姉ちゃんがお世話してあげるからねっ！", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "魔族", "久野美咲", 105001, "ミサキ", "ファッション誌鑑賞、コスメ集め", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 14, "ルーセント学院", 120, 22, 1, 11, 3, "ちょっとおませな恋に恋する女の子", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "ヒューマン", "三石琴乃", 105101, "ミツキ", "研究、実験", "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 13, "トワイライトキャラバン", 166, 53, 3, 27, 7, "実験が趣味の危険な科学者", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "獣人族", "徳井青空", 105201, "リマ", "毛繕い、お喋り", "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 11, "牧場（エリザベスパーク）", 150, 100, 3, 17, 14, "乙女チックなもふもふアニマル", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "ヒューマン", "辻あゆみ", 105301, "モニカ", "お菓子屋通い", "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 15, "ヴァイスフリューゲル　ランドソル支部", 140, 33, 7, 17, 28, "見た目も中身もお子ちゃまな異国の軍人", 0);
