INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "ヒューマン", "金元寿子", 105701, "ジータ", "冒険、おしゃべり", "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", "", "？？？", 156, 45, 3, 17, 10, "空への冒険を夢見る騎空士の少女", 0);
