INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "ヒューマン", "悠木碧", 107701, "スズメ（サマー）", "ご奉仕", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 9, "サレンディア救護院", 154, 43, 12, 15, 12, "お嬢さまのためにがんばるドジっ娘メイド", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "獣人族", "立花理香", 107801, "キャル（サマー）", "猫と遊ぶ", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 1, "美食殿", 152, 39, 9, 14, 2, "行き倒れの謎のネコミミ魔法使い", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("AB", "獣人族", "沼倉愛美", 107901, "タマキ（サマー）", "猫とたわむれること", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 12, "メルクリウス財団", 158, 48, 3, 19, 1, "弱きを助け強きをくじく猫娘", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "ヒューマン", "田所あずさ", 108001, "ミフユ（サマー）", "傭兵などのアルバイト", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 12, "メルクリウス財団", 163, 49, 11, 20, 11, "仕事も私事も効率優先な傭兵少女", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("AB", "魔族", "大坪由佳", 108101, "シノブ（ハロウィン）", "占い", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 7, "悪魔偽王国軍（ディアボロス）", 157, 42, 12, 18, 22, "占いが得意な霊能少女", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("B", "魔族", "雨宮天", 108201, "ミヤコ（ハロウィン）", "プリンを食べること", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 7, "悪魔偽王国軍（ディアボロス）", 130, 32, 1, 14, 23, "プリン大好きゴースト娘", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "魔族", "久野美咲", 108301, "ミサキ（ハロウィン）", "ファッション誌鑑賞、コスメ集め", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 14, "ルーセント学院", 120, 22, 1, 11, 3, "ちょっとおませな恋に恋する女の子", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "ヒューマン", "福原綾香", 108401, "チカ（クリスマス）", "各種楽器", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 4, "カルミナ", 163, 46, 6, 17, 3, "人々を守るために歌う、唱喚士の少女", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("B", "ヒューマン", "植田佳奈", 108501, "クルミ（クリスマス）", "観劇、おままごと", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 9, "サレンディア救護院", 150, 40, 6, 12, 9, "泣き虫で臆病な守ってあげたい女の子", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("B", "ヒューマン", "芹澤優", 108601, "アヤネ（クリスマス）", "屋内でできる遊び", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 9, "サレンディア救護院", 148, 38, 5, 14, 10, "ぷうきちといつも一緒！", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "獣人族", "東山奈央", 108701, "ヒヨリ（ニューイヤー）", "人助け、応援", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 2, "トゥインクルウィッシュ", 155, 44, 8, 16, 27, "人助けが大好き！　前向き格闘娘", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "ヒューマン", "種田梨沙", 108801, "ユイ（ニューイヤー）", "料理、人間観察", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 2, "トゥインクルウィッシュ", 158, 47, 4, 17, 5, "戦闘のサポートが得意な、心優しい少女", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("B", "魔族", "早見沙織", 108901, "レイ（ニューイヤー）", "読書、乗馬、お茶", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 2, "トゥインクルウィッシュ", 163, 46, 1, 18, 12, "クールで何事にも真っ直ぐな剣士", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("B", "魔族", "橋本ちなみ", 109001, "エリコ（バレンタイン）", "実験、裁縫、料理", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 13, "トワイライトキャラバン", 154, 43, 7, 16, 30, "運命の相手に一途すぎる乙女", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "ヒューマン", "生天目仁美", 109101, "シズル（バレンタイン）", "家事全般", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 3, "ラビリンス", 168, 54, 10, 18, 24, "お姉ちゃんがお世話してあげるからねっ！", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("AB", "ヒューマン", "日笠陽子", 109201, "アン", "読書", "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", "", "？？？", 156, 55, 12, 17, 1, "英霊と契約を結んだマナリアの天才王女", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "ヒューマン", "こやまきみこ", 109301, "ルゥ", "食べること、眠ること", "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", "", "？？？", 144, 45, 2, 16, 4, "マナリア魔法学院の新入生", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("B", "半人半竜", "福原綾香", 109401, "グレア", "ピアノ", "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", "", "？？？", 167, 67, 11, 17, 3, "人を超越した力を有す心優しい竜姫", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("AB", "ヒューマン", "長妻樹里", 109501, "クウカ（オーエド）", "小説を読むこと", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 15, "ヴァイスフリューゲル　ランドソル支部", 157, 49, 11, 18, 19, "妄想大好き！　ほんとは照れ屋な女の子", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("O", "ヒューマン", "佐藤聡美", 109601, "ニノン（オーエド）", "忍法開発", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 15, "ヴァイスフリューゲル　ランドソル支部", 163, 51, 8, 16, 31, "トーゴクの神秘、オシエテクダサイ！", 0);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("?", "鬼族", "水瀬いのり", 109701, "レム", "演劇鑑賞、詩文", "", "", "？？？", 154, "??", 2, 17, 2, "鬼がかりの万能妹メイド", 0);
