INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("?", "ハーフエルフ", "高橋李依", 109901, "エミリア", "パックの毛繕い、勉強", "", "", "？？？", 164, "??", 9, "??", 23, "銀髪のおっとりハーフエルフ", 0);
