INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "ヒューマン", "三石琴乃", 117501, "ミツキ（オーエド）", "研究、実験", "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 13, "トワイライトキャラバン", 166, 53, 3, 27, 7, "実験が趣味の危険な科学者", 0);
