INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("A", "獣人族", "東山奈央", 122401, "ヒヨリ（サマー）", "人助け、応援", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 2, "トゥインクルウィッシュ", 155, 44, 8, 16, 27, "人助けが大好き！　前向き格闘娘", 0);
